import boto3
import json
import uuid
from datetime import datetime
from typing import Dict, List, Optional, Any


class SQSPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        self.queue_url = queue_url
        self.sqs_client = boto3.client('sqs', region_name=region_name)
    
    def publish_user_data(self, user_data: Dict[str, Any]) -> Dict[str, Any]:
        message_id = str(uuid.uuid4())
        timestamp = datetime.utcnow().isoformat()
        
        message_body = {
            'message_id': message_id,
            'timestamp': timestamp,
            'user_data': user_data
        }
        
        response = self.sqs_client.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(message_body),
            MessageAttributes={
                'MessageType': {
                    'StringValue': 'UserData',
                    'DataType': 'String'
                },
                'ContainsPII': {
                    'StringValue': 'true',
                    'DataType': 'String'
                }
            }
        )
        
        return {
            'message_id': message_id,
            'sqs_message_id': response['MessageId'],
            'timestamp': timestamp
        }
    
    def publish_batch_user_data(self, users_data: List[Dict[str, Any]]) -> Dict[str, Any]:
        entries = []
        
        for idx, user_data in enumerate(users_data):
            message_id = str(uuid.uuid4())
            timestamp = datetime.utcnow().isoformat()
            
            message_body = {
                'message_id': message_id,
                'timestamp': timestamp,
                'user_data': user_data
            }
            
            entry = {
                'Id': str(idx),
                'MessageBody': json.dumps(message_body),
                'MessageAttributes': {
                    'MessageType': {
                        'StringValue': 'UserData',
                        'DataType': 'String'
                    },
                    'ContainsPII': {
                        'StringValue': 'true',
                        'DataType': 'String'
                    }
                }
            }
            entries.append(entry)
        
        successful = []
        failed = []
        
        for i in range(0, len(entries), 10):
            batch = entries[i:i+10]
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=batch
            )
            
            if 'Successful' in response:
                successful.extend(response['Successful'])
            
            if 'Failed' in response:
                failed.extend(response['Failed'])
        
        return {
            'successful_count': len(successful),
            'failed_count': len(failed),
            'successful': successful,
            'failed': failed
        }
    
    def publish_user_profile(self, user_id: str, email: str, phone_number: str, 
                            address: Dict[str, str], additional_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        user_data = {
            'user_id': user_id,
            'email': email,
            'phone_number': phone_number,
            'address': address
        }
        
        if additional_data:
            user_data.update(additional_data)
        
        return self.publish_user_data(user_data)
    
    def publish_user_update(self, user_id: str, updated_fields: Dict[str, Any]) -> Dict[str, Any]:
        message_id = str(uuid.uuid4())
        timestamp = datetime.utcnow().isoformat()
        
        message_body = {
            'message_id': message_id,
            'timestamp': timestamp,
            'event_type': 'user_update',
            'user_id': user_id,
            'updated_fields': updated_fields
        }
        
        response = self.sqs_client.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(message_body),
            MessageAttributes={
                'MessageType': {
                    'StringValue': 'UserUpdate',
                    'DataType': 'String'
                },
                'ContainsPII': {
                    'StringValue': 'true',
                    'DataType': 'String'
                },
                'UserId': {
                    'StringValue': user_id,
                    'DataType': 'String'
                }
            }
        )
        
        return {
            'message_id': message_id,
            'sqs_message_id': response['MessageId'],
            'timestamp': timestamp
        }
    
    def publish_user_deletion(self, user_id: str, reason: Optional[str] = None) -> Dict[str, Any]:
        message_id = str(uuid.uuid4())
        timestamp = datetime.utcnow().isoformat()
        
        message_body = {
            'message_id': message_id,
            'timestamp': timestamp,
            'event_type': 'user_deletion',
            'user_id': user_id,
            'reason': reason
        }
        
        response = self.sqs_client.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(message_body),
            MessageAttributes={
                'MessageType': {
                    'StringValue': 'UserDeletion',
                    'DataType': 'String'
                },
                'UserId': {
                    'StringValue': user_id,
                    'DataType': 'String'
                }
            }
        )
        
        return {
            'message_id': message_id,
            'sqs_message_id': response['MessageId'],
            'timestamp': timestamp
        }


class FIFOSQSPublisher(SQSPublisher):
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        super().__init__(queue_url, region_name)
    
    def publish_user_data(self, user_data: Dict[str, Any], message_group_id: str = 'default') -> Dict[str, Any]:
        message_id = str(uuid.uuid4())
        timestamp = datetime.utcnow().isoformat()
        
        message_body = {
            'message_id': message_id,
            'timestamp': timestamp,
            'user_data': user_data
        }
        
        response = self.sqs_client.send_message(
            QueueUrl=self.queue_url,
            MessageBody=json.dumps(message_body),
            MessageGroupId=message_group_id,
            MessageDeduplicationId=message_id,
            MessageAttributes={
                'MessageType': {
                    'StringValue': 'UserData',
                    'DataType': 'String'
                },
                'ContainsPII': {
                    'StringValue': 'true',
                    'DataType': 'String'
                }
            }
        )
        
        return {
            'message_id': message_id,
            'sqs_message_id': response['MessageId'],
            'timestamp': timestamp,
            'sequence_number': response.get('SequenceNumber')
        }
    
    def publish_user_profile(self, user_id: str, email: str, phone_number: str, 
                            address: Dict[str, str], additional_data: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        user_data = {
            'user_id': user_id,
            'email': email,
            'phone_number': phone_number,
            'address': address
        }
        
        if additional_data:
            user_data.update(additional_data)
        
        return self.publish_user_data(user_data, message_group_id=user_id)


